import React, { forwardRef, useCallback } from 'react';
import { cn } from '@/utils/cn';
import { StepItem } from './StepItem';
import type { CheckoutStepperProps } from './CheckoutStepper.types';
import type { StepStatus } from '@/types';

function getStatus(index: number, activeStep: number): StepStatus {
  if (index < activeStep) return 'completed';
  if (index === activeStep) return 'active';
  return 'pending';
}

export const CheckoutStepper = forwardRef<HTMLOListElement, CheckoutStepperProps>(
  function CheckoutStepper(
    {
      steps,
      activeStep,
      orientation = 'horizontal',
      onStepClick,
      showLabels = true,
      showDescriptions = false,
      connectorAnimation = true,
      minStepWidth = 100,
      classNames,
      className,
      style,
    },
    ref
  ) {
    // Arrow-key navigation between clickable step buttons
    const handleKeyDown = useCallback(
      (e: React.KeyboardEvent<HTMLElement>): void => {
        if (!onStepClick) return;
        const isHoriz = orientation === 'horizontal';
        const isNext = isHoriz ? e.key === 'ArrowRight' : e.key === 'ArrowDown';
        const isPrev = isHoriz ? e.key === 'ArrowLeft' : e.key === 'ArrowUp';
        if (!isNext && !isPrev) return;
        e.preventDefault();
        const buttons = Array.from(
          e.currentTarget.querySelectorAll<HTMLButtonElement>('button[data-step-btn]')
        );
        const idx = buttons.findIndex((b) => b === document.activeElement);
        if (idx < 0) return;
        const target = isPrev ? buttons[idx - 1] : buttons[idx + 1];
        target?.focus();
      },
      [orientation, onStepClick]
    );

    return (
      // eslint-disable-next-line jsx-a11y/no-static-element-interactions
      <div onKeyDown={handleKeyDown}>
        <ol
          ref={ref}
          aria-label="Checkout steps"
          style={
            orientation === 'horizontal'
              ? { gridTemplateColumns: `repeat(${steps.length}, minmax(${minStepWidth}px, 1fr))`, ...style }
              : style
          }
          className={cn(
            orientation === 'horizontal' ? 'grid w-full' : 'flex flex-col',
            classNames?.root,
            className
          )}
        >
          {steps.map((step, index) => (
            <StepItem
              key={step.id}
              step={step}
              index={index}
              status={getStatus(index, activeStep)}
              orientation={orientation}
              isFirst={index === 0}
              isLast={index === steps.length - 1}
              showLabel={showLabels}
              showDescription={showDescriptions}
              connectorAnimation={connectorAnimation}
              onClick={
                getStatus(index, activeStep) === 'completed' && onStepClick
                  ? (): void => onStepClick(index)
                  : undefined
              }
              classNames={classNames}
            />
          ))}
        </ol>
      </div>
    );
  }
);
