﻿import React, { forwardRef, useCallback, useEffect, useMemo, useRef } from 'react';
import { cn } from '@/utils/cn';
import { formatPrice } from '@/utils/formatPrice';
import { Button } from '@/primitives/Button';
import { IconButton } from '@/primitives/IconButton';
import { CloseIcon, ShoppingCartIcon } from '@icons';
import { CartItemComponent } from './CartItem';
import type { CartDrawerProps } from './CartDrawer.types';

// ─── Focus trap ───────────────────────────────────────────────────────────────

const FOCUSABLE_SELECTORS = [
  'a[href]',
  'button:not([disabled])',
  'input:not([disabled])',
  'select:not([disabled])',
  'textarea:not([disabled])',
  '[tabindex]:not([tabindex="-1"])',
].join(', ');

function useFocusTrap(containerRef: React.RefObject<HTMLDivElement>, isActive: boolean): void {
  useEffect(() => {
    if (!isActive) return;
    const container = containerRef.current;
    if (!container) return;

    const getFocusable = (): HTMLElement[] =>
      Array.from(container.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTORS));

    const previousFocus = document.activeElement as HTMLElement | null;

    // Move focus into the panel immediately
    const focusable = getFocusable();
    if (focusable.length > 0) {
      focusable[0].focus();
    }

    const onKeyDown = (e: KeyboardEvent): void => {
      if (e.key !== 'Tab') return;
      const els = getFocusable();
      if (els.length === 0) return;
      const first = els[0];
      const last = els[els.length - 1];
      if (e.shiftKey) {
        if (document.activeElement === first) {
          e.preventDefault();
          last.focus();
        }
      } else {
        if (document.activeElement === last) {
          e.preventDefault();
          first.focus();
        }
      }
    };

    document.addEventListener('keydown', onKeyDown);
    return (): void => {
      document.removeEventListener('keydown', onKeyDown);
      previousFocus?.focus();
    };
  }, [isActive, containerRef]);
}

// ─── CartDrawer ───────────────────────────────────────────────────────────────

const TITLE_ID = 'euk-cart-drawer-title';

/**
 * Slide-in cart drawer driven by `useDisclosure` (or any boolean open state).
 * Includes focus trap, ESC-to-close, accessible dialog semantics, and smooth
 * CSS transitions — no animation library required.
 */
export const CartDrawer = forwardRef<HTMLDivElement, CartDrawerProps>(function CartDrawer(
  {
    isOpen,
    onClose,
    items,
    title = 'Your Cart',
    position = 'right',
    currency = '$',
    showSubtotal = true,
    showItemCount = true,
    emptyStateMessage = 'Your cart is empty',
    emptyStateIcon,
    onQuantityChange,
    onRemoveItem,
    onCheckout,
    onContinueShopping,
    classNames,
    className,
    style,
  },
  ref
) {
  const panelRef = useRef<HTMLDivElement>(null);

  // ── Subtotal ──────────────────────────────────────────────────────────────
  const subtotal = useMemo(
    () => items.reduce((sum, item) => sum + item.price * item.quantity, 0),
    [items]
  );

  const itemCount = useMemo(() => items.reduce((sum, item) => sum + item.quantity, 0), [items]);

  // ── Memoised handlers (stable refs for CartItem.memo) ─────────────────────
  const handleQuantityChange = useCallback(
    (id: string, quantity: number): void => onQuantityChange(id, quantity),
    [onQuantityChange]
  );

  const handleRemoveItem = useCallback((id: string): void => onRemoveItem(id), [onRemoveItem]);

  // ── ESC to close ──────────────────────────────────────────────────────────
  useEffect(() => {
    if (!isOpen) return;
    const onKeyDown = (e: KeyboardEvent): void => {
      if (e.key === 'Escape') onClose();
    };
    document.addEventListener('keydown', onKeyDown);
    return (): void => document.removeEventListener('keydown', onKeyDown);
  }, [isOpen, onClose]);

  // ── Focus trap ────────────────────────────────────────────────────────────
  useFocusTrap(panelRef, isOpen);

  // ── Slide direction ───────────────────────────────────────────────────────
  const panelSlide = isOpen
    ? 'translate-x-0'
    : position === 'right'
      ? 'translate-x-full'
      : '-translate-x-full';

  return (
    <div
      ref={ref}
      style={style}
      aria-hidden={!isOpen || undefined}
      className={cn('fixed inset-0 z-50', !isOpen && 'pointer-events-none', className)}
    >
      {/* ── Backdrop ──────────────────────────────────────────────────── */}
      <div
        aria-hidden="true"
        data-testid="cart-drawer-backdrop"
        onClick={onClose}
        className={cn(
          'absolute inset-0 bg-[color:var(--clf-color-overlay)]',
          'transition-opacity duration-[var(--clf-duration-slow)]',
          isOpen ? 'opacity-100' : 'opacity-0',
          classNames?.overlay
        )}
      />

      {/* ── Panel ─────────────────────────────────────────────────────── */}
      <div
        ref={panelRef}
        role="dialog"
        aria-modal="true"
        aria-labelledby={TITLE_ID}
        className={cn(
          'absolute inset-y-0 flex w-full flex-col sm:max-w-[400px]',
          position === 'right' ? 'right-0' : 'left-0',
          'bg-[color:var(--clf-color-surface)] shadow-lg',
          'transition-transform duration-[var(--clf-duration-slow)]',
          panelSlide,
          classNames?.panel
        )}
      >
        {/* ── Header ──────────────────────────────────────────────────── */}
        <div
          className={cn(
            'flex shrink-0 items-start justify-between gap-3',
            'border-b border-[color:var(--clf-color-border)] px-4 py-3',
            classNames?.header
          )}
        >
          <div>
            <h2 id={TITLE_ID} className="text-lg font-semibold leading-snug">
              {title}
            </h2>
            {showItemCount && (
              <p className="text-xs text-[color:var(--clf-color-muted-foreground)]">
                {itemCount} {itemCount === 1 ? 'item' : 'items'}
              </p>
            )}
          </div>
          <IconButton
            icon={<CloseIcon />}
            aria-label="Close cart"
            variant="ghost"
            size="sm"
            onClick={onClose}
          />
        </div>

        {/* ── Item list / empty state ──────────────────────────────────── */}
        <div className={cn('flex-1 overflow-y-auto px-4', classNames?.list)}>
          {items.length === 0 ? (
            <div className="flex h-full flex-col items-center justify-center gap-3 py-16 text-center">
              {emptyStateIcon ?? <ShoppingCartIcon />}
              <p className="text-sm text-[color:var(--clf-color-muted-foreground)]">
                {emptyStateMessage}
              </p>
            </div>
          ) : (
            <ul aria-label="Cart items" className="divide-y divide-[color:var(--clf-color-border)]">
              {items.map((item) => (
                <li key={item.id}>
                  <CartItemComponent
                    item={item}
                    currency={currency}
                    onQuantityChange={handleQuantityChange}
                    onRemove={handleRemoveItem}
                  />
                </li>
              ))}
            </ul>
          )}
        </div>

        {/* ── Footer ──────────────────────────────────────────────────── */}
        <div
          className={cn(
            'shrink-0 space-y-3 border-t border-[color:var(--clf-color-border)] px-4 py-4',
            classNames?.footer
          )}
        >
          {showSubtotal && items.length > 0 && (
            <div className="flex items-center justify-between">
              <span className="text-sm text-[color:var(--clf-color-muted-foreground)]">
                Subtotal
              </span>
              <span className="text-base font-semibold">{formatPrice(subtotal, currency)}</span>
            </div>
          )}
          <Button
            variant="primary"
            fullWidth
            isDisabled={items.length === 0}
            onClick={onCheckout}
            aria-label="Proceed to checkout"
          >
            Checkout
          </Button>
          <Button variant="ghost" fullWidth onClick={onContinueShopping ?? onClose}>
            Continue Shopping
          </Button>
        </div>
      </div>
    </div>
  );
});
