﻿import React, { forwardRef } from 'react';
import { cn } from '@/utils/cn';
import type { BadgeVariant } from '@/types';

const variantClasses: Record<BadgeVariant, string> = {
  sale: 'bg-[color:var(--clf-color-badge-sale-bg)] text-[color:var(--clf-color-badge-sale-text)]',
  new: 'bg-[color:var(--clf-color-badge-new-bg)] text-[color:var(--clf-color-badge-new-text)]',
  'out-of-stock':
    'bg-[color:var(--clf-color-badge-oos-bg)] text-[color:var(--clf-color-badge-oos-text)]',
  custom: '',
};

export interface BadgeProps {
  /** Display variant determining the color scheme */
  variant?: BadgeVariant;
  /** Text displayed inside the badge */
  label: string;
  className?: string;
  style?: React.CSSProperties;
}

export const Badge = forwardRef<HTMLSpanElement, BadgeProps>(function Badge(
  { variant = 'custom', label, className, style },
  ref
) {
  return (
    <span
      ref={ref}
      style={style}
      className={cn(
        'inline-flex items-center rounded-md px-2 py-0.5 text-xs font-semibold',
        variantClasses[variant],
        className
      )}
    >
      {label}
    </span>
  );
});
