import React, { forwardRef } from 'react';
import { cn } from '@/utils/cn';
import { SpinnerIcon } from '@icons/SpinnerIcon';
import type { ButtonVariant, ButtonSize } from '@/types';

const variantClasses: Record<ButtonVariant, string> = {
  primary: 'bg-primary text-primary-foreground hover:bg-primary-hover focus-visible:ring-primary',
  secondary:
    'bg-secondary text-secondary-foreground hover:bg-secondary-hover focus-visible:ring-secondary',
  ghost: 'bg-transparent text-primary hover:bg-primary/10 focus-visible:ring-primary',
  danger: 'bg-danger text-danger-foreground hover:bg-danger-hover focus-visible:ring-danger',
};

const sizeClasses: Record<ButtonSize, string> = {
  sm: 'h-8 px-3 text-sm gap-1.5',
  md: 'h-10 px-4 text-sm gap-2',
  lg: 'h-12 px-6 text-base gap-2',
};

type ButtonElement = HTMLButtonElement | HTMLAnchorElement;

interface ButtonBaseProps {
  /** Visual style variant */
  variant?: ButtonVariant;
  /** Size of the button */
  size?: ButtonSize;
  /** Show a loading spinner and disable interaction */
  isLoading?: boolean;
  /** Disable the button */
  isDisabled?: boolean;
  /** Icon rendered before children */
  leftIcon?: React.ReactNode;
  /** Icon rendered after children */
  rightIcon?: React.ReactNode;
  /** Stretch to fill the parent width */
  fullWidth?: boolean;
  children?: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
}

type PolymorphicButtonProps<C extends React.ElementType = 'button'> = ButtonBaseProps & {
  /** Render as a different element (e.g. "a" for link buttons) */
  as?: C;
} & Omit<React.ComponentPropsWithoutRef<C>, keyof ButtonBaseProps | 'as'>;

function ButtonInner<C extends React.ElementType = 'button'>(
  {
    as,
    variant = 'primary',
    size = 'md',
    isLoading = false,
    isDisabled = false,
    leftIcon,
    rightIcon,
    fullWidth = false,
    children,
    className,
    style,
    onClick,
    ...rest
  }: PolymorphicButtonProps<C>,
  ref: React.ForwardedRef<ButtonElement>
): React.ReactElement {
  const Tag = (as ?? 'button') as React.ElementType;
  const disabled = isDisabled || isLoading;

  return (
    <Tag
      ref={ref}
      aria-disabled={disabled || undefined}
      disabled={Tag === 'button' ? disabled : undefined}
      onClick={disabled ? undefined : onClick}
      style={style}
      className={cn(
        'inline-flex items-center justify-center rounded-md font-medium whitespace-nowrap transition-colors',
        'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2',
        variantClasses[variant],
        sizeClasses[size],
        fullWidth && 'w-full',
        disabled && 'pointer-events-none opacity-50',
        className
      )}
      {...rest}
    >
      {isLoading ? (
        <SpinnerIcon />
      ) : (
        <>
          {leftIcon && <span aria-hidden="true">{leftIcon}</span>}
          {children}
          {rightIcon && <span aria-hidden="true">{rightIcon}</span>}
        </>
      )}
    </Tag>
  );
}

export const Button = forwardRef(ButtonInner) as <C extends React.ElementType = 'button'>(
  props: PolymorphicButtonProps<C> & { ref?: React.ForwardedRef<ButtonElement> }
) => React.ReactElement;
