﻿import React, { forwardRef, useEffect } from 'react';
import { cn } from '@/utils/cn';
import type { PageLoaderProps, LoaderSize } from './PageLoader.types';

// ─── Keyframe injection (once per document) ───────────────────────────────────

const STYLES_ID = 'euk-page-loader-styles';
const LOADER_CSS = `
@keyframes euk-spin    { to { transform: rotate(360deg); } }
@keyframes euk-spin-ccw { to { transform: rotate(-360deg); } }
@keyframes euk-bounce {
  0%, 80%, 100% { transform: translateY(0) scale(0.9); opacity: 0.45; }
  40%           { transform: translateY(-55%) scale(1.1); opacity: 1; }
}
@keyframes euk-bar {
  0%, 100% { transform: scaleY(0.3); }
  50%      { transform: scaleY(1); }
}
@keyframes euk-pulse-ring {
  0%   { transform: scale(0.75); opacity: 0.85; }
  100% { transform: scale(2.1);  opacity: 0; }
}
@keyframes euk-pulse-core {
  0%, 100% { transform: scale(1); }
  50%      { transform: scale(0.82); }
}
`;

function useLoaderStyles(): void {
  useEffect(() => {
    if (typeof document === 'undefined' || document.getElementById(STYLES_ID)) return;
    const el = document.createElement('style');
    el.id = STYLES_ID;
    el.textContent = LOADER_CSS;
    document.head.appendChild(el);
  }, []);
}

// ─── Size resolution ──────────────────────────────────────────────────────────

const SIZE_PX: Record<LoaderSize, number> = { sm: 24, md: 40, lg: 56, xl: 72 };

function resolvePx(size: LoaderSize | number): number {
  return typeof size === 'number' ? size : SIZE_PX[size];
}

// ─── Variant sub-components ───────────────────────────────────────────────────

function SpinnerVariant({ size, color }: { size: number; color: string }): React.ReactElement {
  const bw = Math.max(2, Math.round(size / 12));
  const glow = Math.max(2, Math.round(bw * 2.5));
  const innerInset = Math.round(size * 0.22);
  const dotInset = Math.round(size * 0.42);

  return (
    <div style={{ position: 'relative', width: size, height: size }}>
      {/* Outer track — faded full ring */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          borderRadius: '50%',
          border: `${bw}px solid ${color}`,
          opacity: 0.15,
        }}
      />
      {/* Outer arc — spins, with glow */}
      <div
        style={{
          position: 'absolute',
          inset: 0,
          borderRadius: '50%',
          border: `${bw}px solid transparent`,
          borderTopColor: color,
          animation: 'euk-spin 0.9s linear infinite',
          filter: `drop-shadow(0 0 ${glow}px ${color})`,
        }}
      />
      {/* Inner track — faded full ring */}
      <div
        style={{
          position: 'absolute',
          inset: innerInset,
          borderRadius: '50%',
          border: `${bw}px solid ${color}`,
          opacity: 0.12,
        }}
      />
      {/* Inner arc — counter-spins */}
      <div
        style={{
          position: 'absolute',
          inset: innerInset,
          borderRadius: '50%',
          border: `${bw}px solid transparent`,
          borderBottomColor: color,
          animation: 'euk-spin-ccw 0.65s linear infinite',
        }}
      />
      {/* Center dot with glow */}
      <div
        style={{
          position: 'absolute',
          inset: dotInset,
          borderRadius: '50%',
          backgroundColor: color,
          opacity: 0.9,
          filter: `drop-shadow(0 0 ${Math.round(glow * 0.8)}px ${color})`,
        }}
      />
    </div>
  );
}

function DotsVariant({ size, color }: { size: number; color: string }): React.ReactElement {
  const dotSize = Math.max(6, Math.round(size * 0.24));
  const gap = Math.max(4, Math.round(size * 0.14));
  const glow = Math.max(2, Math.round(dotSize * 0.5));

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap }}>
      {[0, 1, 2].map((i) => (
        <div
          key={i}
          style={{
            width: dotSize,
            height: dotSize,
            borderRadius: '50%',
            backgroundColor: color,
            animation: `euk-bounce 1.3s ease-in-out ${i * 0.18}s infinite`,
            filter: `drop-shadow(0 0 ${glow}px ${color})`,
          }}
        />
      ))}
    </div>
  );
}

function BarsVariant({ size, color }: { size: number; color: string }): React.ReactElement {
  const barW = Math.max(3, Math.round(size * 0.1));
  const barH = Math.round(size * 0.65);
  const gap = Math.max(3, Math.round(size * 0.08));

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap, height: size }}>
      {[0, 1, 2, 3, 4].map((i) => (
        <div
          key={i}
          style={{
            width: barW,
            height: barH,
            borderRadius: barW,
            backgroundColor: color,
            animation: `euk-bar 1s ease-in-out ${i * 0.12}s infinite`,
            transformOrigin: 'center',
          }}
        />
      ))}
    </div>
  );
}

function PulseVariant({ size, color }: { size: number; color: string }): React.ReactElement {
  const coreInset = Math.round(size * 0.3);
  const coreSize = size - coreInset * 2;
  const glow = Math.max(3, Math.round(coreSize * 0.5));

  return (
    <div style={{ position: 'relative', width: size, height: size }}>
      {[0, 1, 2].map((i) => (
        <div
          key={i}
          style={{
            position: 'absolute',
            inset: 0,
            borderRadius: '50%',
            border: `2px solid ${color}`,
            animation: `euk-pulse-ring 2s ease-out ${i * 0.6}s infinite`,
          }}
        />
      ))}
      <div
        style={{
          position: 'absolute',
          inset: coreInset,
          borderRadius: '50%',
          backgroundColor: color,
          animation: 'euk-pulse-core 2s ease-in-out infinite',
          filter: `drop-shadow(0 0 ${glow}px ${color})`,
        }}
      />
    </div>
  );
}

// ─── PageLoader ───────────────────────────────────────────────────────────────

const POSITION_CLASS: Record<string, string> = {
  fullscreen: 'fixed inset-0 z-[9999]',
  overlay: 'absolute inset-0 z-10',
  inline: 'relative',
};

export const PageLoader = forwardRef<HTMLDivElement, PageLoaderProps>(function PageLoader(
  {
    isVisible = true,
    variant = 'spinner',
    size = 'md',
    color = 'var(--clf-color-primary)',
    position = 'inline',
    backdrop = false,
    text,
    className,
    style,
  },
  ref
) {
  useLoaderStyles();

  const px = resolvePx(size);
  const showBackdrop = backdrop && position !== 'inline';

  return (
    <div
      ref={ref}
      role="status"
      aria-label={text ?? 'Loading'}
      aria-busy={isVisible}
      aria-hidden={!isVisible || undefined}
      style={{
        transition: 'opacity 0.25s ease',
        opacity: isVisible ? 1 : 0,
        pointerEvents: isVisible ? undefined : 'none',
        ...style,
      }}
      className={cn(
        POSITION_CLASS[position],
        'flex flex-col items-center justify-center gap-3',
        className
      )}
    >
      {showBackdrop && (
        <div
          aria-hidden="true"
          className="absolute inset-0 bg-[color:var(--clf-color-surface)]/80 backdrop-blur-sm"
        />
      )}

      <div className="relative z-10">
        {variant === 'spinner' && <SpinnerVariant size={px} color={color} />}
        {variant === 'dots' && <DotsVariant size={px} color={color} />}
        {variant === 'bars' && <BarsVariant size={px} color={color} />}
        {variant === 'pulse' && <PulseVariant size={px} color={color} />}
      </div>

      {text && (
        <p className="relative z-10 text-sm font-medium tracking-wide text-[color:var(--clf-color-muted-foreground)]">
          {text}
        </p>
      )}
    </div>
  );
});
