﻿import React from 'react';
import { cn } from '@/utils/cn';
import { CheckIcon } from '@icons/CheckIcon';
import type { Step, StepStatus } from '@/types';
import type { StepperOrientation, CheckoutStepperClassNames } from './CheckoutStepper.types';

// ─── Internal props ───────────────────────────────────────────────────────────

export interface StepItemProps {
  step: Step;
  index: number;
  status: StepStatus;
  orientation: StepperOrientation;
  isFirst: boolean;
  isLast: boolean;
  showLabel: boolean;
  showDescription: boolean;
  connectorAnimation: boolean;
  onClick?: () => void;
  classNames?: CheckoutStepperClassNames;
}

// ─── Shared helpers ───────────────────────────────────────────────────────────

const BUTTON_FOCUS =
  'rounded focus-visible:outline-none focus-visible:ring-2 ' +
  'focus-visible:ring-[color:var(--clf-color-primary)] focus-visible:ring-offset-2';

function StepCircle({
  step,
  index,
  status,
  className,
}: {
  step: Step;
  index: number;
  status: StepStatus;
  className?: string;
}): React.ReactElement {
  const isCompleted = status === 'completed';
  const isActive = status === 'active';
  const isPending = status === 'pending';

  return (
    <div
      aria-hidden="true"
      className={cn(
        'relative z-10 flex h-8 w-8 shrink-0 items-center justify-center rounded-full',
        'text-sm font-semibold select-none',
        'transition-all duration-[var(--clf-duration-base)]',
        (isCompleted || isActive) &&
          'bg-[color:var(--clf-color-primary)] text-[color:var(--clf-color-primary-foreground)]',
        isPending &&
          'border-2 border-[color:var(--clf-color-border)] bg-[color:var(--clf-color-surface-raised)] text-[color:var(--clf-color-muted-foreground)]',
        className
      )}
      style={
        isActive
          ? { boxShadow: '0 0 0 3px var(--clf-color-surface), 0 0 0 6px var(--clf-color-primary)' }
          : undefined
      }
    >
      {step.icon ?? (isCompleted ? <CheckIcon /> : <span>{index + 1}</span>)}
    </div>
  );
}

function StepLabel({
  step,
  status,
  showLabel,
  showDescription,
  orientation,
  labelClassName,
  descriptionClassName,
}: {
  step: Step;
  status: StepStatus;
  showLabel: boolean;
  showDescription: boolean;
  orientation: StepperOrientation;
  labelClassName?: string;
  descriptionClassName?: string;
}): React.ReactElement | null {
  if (!showLabel && !showDescription) return null;
  const isActive = status === 'active';
  const isPending = status === 'pending';

  return (
    <div
      className={cn(
        'flex flex-col gap-0.5',
        orientation === 'horizontal' && 'items-center text-center'
      )}
    >
      {showLabel && (
        <span
          className={cn(
            'text-xs font-medium leading-snug whitespace-nowrap',
            'transition-colors duration-[var(--clf-duration-base)]',
            isActive && 'font-semibold text-[color:var(--clf-color-primary)]',
            isPending && 'text-[color:var(--clf-color-muted-foreground)]',
            labelClassName
          )}
        >
          {step.label}
        </span>
      )}
      {showDescription && step.description && (
        <span
          className={cn(
            'text-[10px] leading-snug text-[color:var(--clf-color-muted-foreground)]',
            descriptionClassName
          )}
        >
          {step.description}
        </span>
      )}
    </div>
  );
}

function Connector({
  orientation,
  filled,
  animated,
  className,
}: {
  orientation: StepperOrientation;
  filled: boolean;
  animated: boolean;
  className?: string;
}): React.ReactElement {
  if (orientation === 'horizontal') {
    return (
      <div className={cn('relative h-0.5 w-full', className)} aria-hidden="true">
        <div className="absolute inset-0 h-full w-full rounded-full bg-[color:var(--clf-color-border)]" />
        <div
          className={cn(
            'absolute inset-0 h-full rounded-full bg-[color:var(--clf-color-primary)]',
            animated && 'transition-[width] duration-[var(--clf-duration-slow)]'
          )}
          style={{ width: filled ? '100%' : '0%' }}
        />
      </div>
    );
  }

  return (
    <div className={cn('relative mt-1 w-0.5 flex-1 min-h-6', className)} aria-hidden="true">
      <div className="absolute inset-0 w-full rounded-full bg-[color:var(--clf-color-border)]" />
      <div
        className={cn(
          'absolute top-0 left-0 w-full rounded-full bg-[color:var(--clf-color-primary)]',
          animated && 'transition-[height] duration-[var(--clf-duration-slow)]'
        )}
        style={{ height: filled ? '100%' : '0%' }}
      />
    </div>
  );
}

// ─── StepItem ─────────────────────────────────────────────────────────────────

export function StepItem({
  step,
  index,
  status,
  orientation,
  isFirst,
  isLast,
  showLabel,
  showDescription,
  connectorAnimation,
  onClick,
  classNames,
}: StepItemProps): React.ReactElement {
  const isCompleted = status === 'completed';
  const isActive = status === 'active';
  // Connector fill rules:
  //   left/top connector  → filled if this step is active or completed (prev was completed)
  //   right/bottom connector → filled only when this step is completed
  const prevDone = !status.startsWith('p'); // 'completed' | 'active' → true, 'pending' → false
  const hereDone = isCompleted;

  // group-hover:brightness-90 fires only when an ancestor has class `group` —
  // harmless on non-clickable steps where no such ancestor exists.
  const circleEl = (
    <StepCircle
      step={step}
      index={index}
      status={status}
      className={cn(classNames?.circle, 'group-hover:brightness-90 transition-[filter]')}
    />
  );

  const labelEl = (
    <StepLabel
      step={step}
      status={status}
      showLabel={showLabel}
      showDescription={showDescription}
      orientation={orientation}
      labelClassName={cn(classNames?.label, onClick && 'group-hover:underline underline-offset-2')}
      descriptionClassName={classNames?.description}
    />
  );

  // ── Horizontal ──────────────────────────────────────────────────────────────
  if (orientation === 'horizontal') {
    const inner = onClick ? (
      <button
        type="button"
        data-step-btn=""
        onClick={onClick}
        aria-label={`Go back to ${step.label}`}
        className={cn('group flex flex-col items-center gap-2', BUTTON_FOCUS)}
      >
        {circleEl}
        {labelEl}
      </button>
    ) : (
      <div className="flex flex-col items-center gap-2">
        {circleEl}
        {labelEl}
      </div>
    );

    return (
      <li
        aria-current={isActive ? 'step' : undefined}
        className={cn('relative flex flex-col items-center', classNames?.step)}
      >
        {/* Left half-connector — from prev circle center to this circle center */}
        {!isFirst && (
          <div
            className={cn('absolute top-4 left-0 right-1/2 h-0.5', classNames?.connector)}
            aria-hidden="true"
          >
            <div className="h-full w-full rounded-full bg-[color:var(--clf-color-border)]" />
            <div
              className={cn(
                'absolute inset-0 h-full rounded-full bg-[color:var(--clf-color-primary)]',
                connectorAnimation && 'transition-[width] duration-[var(--clf-duration-slow)]'
              )}
              style={{ width: prevDone ? '100%' : '0%' }}
            />
          </div>
        )}
        {/* Right half-connector — from this circle center to next circle center */}
        {!isLast && (
          <div
            className={cn('absolute top-4 left-1/2 right-0 h-0.5', classNames?.connector)}
            aria-hidden="true"
          >
            <div className="h-full w-full rounded-full bg-[color:var(--clf-color-border)]" />
            <div
              className={cn(
                'absolute inset-0 h-full rounded-full bg-[color:var(--clf-color-primary)]',
                connectorAnimation && 'transition-[width] duration-[var(--clf-duration-slow)]'
              )}
              style={{ width: hereDone ? '100%' : '0%' }}
            />
          </div>
        )}
        {inner}
      </li>
    );
  }

  // ── Vertical ────────────────────────────────────────────────────────────────
  return (
    <li aria-current={isActive ? 'step' : undefined} className={cn('flex gap-4', classNames?.step)}>
      {/* Left column: circle + connector line */}
      <div className="flex flex-col items-center">
        {onClick ? (
          <button
            type="button"
            data-step-btn=""
            onClick={onClick}
            aria-label={`Go back to ${step.label}`}
            className={cn('group', BUTTON_FOCUS)}
          >
            {circleEl}
          </button>
        ) : (
          circleEl
        )}

        {!isLast && (
          <Connector
            orientation="vertical"
            filled={hereDone}
            animated={connectorAnimation}
            className={classNames?.connector}
          />
        )}
      </div>

      {/* Right column: label + description */}
      <div className={cn('flex flex-col justify-center', !isLast && 'pb-8')}>
        {onClick ? (
          <button
            type="button"
            onClick={onClick}
            tabIndex={-1}
            aria-hidden="true"
            className="flex flex-col gap-0.5 text-left cursor-pointer"
          >
            {labelEl}
          </button>
        ) : (
          labelEl
        )}
      </div>
    </li>
  );
}
