﻿import React, { forwardRef, useCallback, useEffect, useRef, useState } from 'react';
import { cn } from '@/utils/cn';
import { formatPrice, calculateDiscount } from '@/utils/formatPrice';
import { useMediaQuery } from '@/hooks/useMediaQuery';
import { Badge } from '@/primitives/Badge';
import { Button } from '@/primitives/Button';
import { IconButton } from '@/primitives/IconButton';
import { StarIcon, HeartIcon, ChevronLeftIcon, ChevronRightIcon } from '@icons';
import type { BadgeVariant } from '@/types';
import type { ProductCardProps } from './ProductCard.types';

// ─── Sub-components ───────────────────────────────────────────────────────────

function StarRating({ rating, count }: { rating: number; count?: number }): React.ReactElement {
  const stars = Math.round(rating);
  return (
    <div className="flex items-center gap-1" role="img" aria-label={`${rating} out of 5 stars`}>
      {Array.from({ length: 5 }, (_, i) => (
        <StarIcon
          key={i}
          className={cn(
            'h-4 w-4',
            i < stars
              ? 'text-[color:var(--clf-color-warning)]'
              : 'text-[color:var(--clf-color-border)]'
          )}
        />
      ))}
      {count !== undefined && (
        <span className="text-xs text-[color:var(--clf-color-muted-foreground)]">({count})</span>
      )}
    </div>
  );
}

function resolveBadgeVariant(product: {
  inStock?: boolean;
  originalPrice?: number;
  price: number;
}): BadgeVariant | null {
  if (product.inStock === false) return 'out-of-stock';
  if (product.originalPrice && product.originalPrice > product.price) return 'sale';
  return null;
}

function SkeletonCard({
  variant,
}: {
  variant: 'default' | 'horizontal' | 'compact';
}): React.ReactElement {
  const isHorizontal = variant === 'horizontal';
  return (
    <div
      aria-busy="true"
      aria-label="Loading product"
      className={cn(
        'w-full animate-pulse rounded-lg bg-[color:var(--clf-color-surface-raised)] overflow-hidden',
        isHorizontal ? 'flex flex-row' : 'flex flex-col'
      )}
    >
      <div
        className={cn(
          'bg-[color:var(--clf-color-border)]',
          isHorizontal ? 'w-40 h-32' : 'w-full h-56'
        )}
      />
      <div className="p-4 flex-1 space-y-3">
        <div className="h-4 bg-[color:var(--clf-color-border)] rounded w-3/4" />
        <div className="h-4 bg-[color:var(--clf-color-border)] rounded w-1/2" />
        <div className="h-8 bg-[color:var(--clf-color-border)] rounded w-full mt-4" />
      </div>
    </div>
  );
}

/**
 * Thumbnail strip — shown below the image in the default variant.
 * Displays up to 5 thumbnails at once; scroll arrows appear when total > 5.
 * The active thumbnail auto-scrolls into view.
 */
function ThumbnailStrip({
  images,
  imageAlts,
  activeIndex,
  onSelect,
  className,
}: {
  images: string[];
  imageAlts: string[];
  activeIndex: number;
  onSelect: (i: number) => void;
  className?: string;
}): React.ReactElement {
  const scrollRef = useRef<HTMLDivElement>(null);
  const needsScrollArrows = images.length > 5;

  // Auto-scroll active thumbnail into view whenever it changes
  useEffect(() => {
    const container = scrollRef.current;
    if (!container) return;
    const activeBtn = container.children[activeIndex] as HTMLElement | undefined;
    if (typeof activeBtn?.scrollIntoView === 'function') {
      activeBtn.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
    }
  }, [activeIndex]);

  const scroll = (dir: 'left' | 'right'): void => {
    scrollRef.current?.scrollBy({ left: dir === 'left' ? -180 : 180, behavior: 'smooth' });
  };

  return (
    <div
      className={cn(
        'flex items-center gap-1 bg-[color:var(--clf-color-surface-raised)]',
        'border-b border-[color:var(--clf-color-border)] px-2 py-2',
        className
      )}
    >
      {/* Left scroll arrow — only visible when > 5 thumbnails */}
      {needsScrollArrows && (
        <button
          aria-label="Scroll thumbnails left"
          onClick={(e) => {
            e.stopPropagation();
            scroll('left');
          }}
          className="shrink-0 p-0.5 rounded text-[color:var(--clf-color-muted-foreground)] hover:text-[color:var(--clf-color-primary)] transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-primary"
        >
          <ChevronLeftIcon />
        </button>
      )}

      {/* Scrollable thumbnail row — hides native scrollbar via CSS */}
      <div
        ref={scrollRef}
        role="tablist"
        aria-label="Product images"
        className="flex flex-1 min-w-0 gap-2 overflow-x-auto scroll-smooth [&::-webkit-scrollbar]:hidden"
        style={{ scrollbarWidth: 'none' }}
      >
        {images.map((src, i) => {
          const alt = imageAlts[i] ?? `${i + 1} of ${images.length}`;
          const isActive = i === activeIndex;
          return (
            <button
              key={i}
              role="tab"
              aria-selected={isActive}
              aria-label={alt}
              onClick={(e) => {
                e.stopPropagation();
                onSelect(i);
              }}
              className={cn(
                'relative shrink-0 h-14 w-14 rounded overflow-hidden border-2 transition-all duration-[var(--clf-duration-base)]',
                'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-1',
                isActive
                  ? 'border-[color:var(--clf-color-primary)] shadow-sm scale-105'
                  : 'border-[color:var(--clf-color-border)] opacity-55 hover:opacity-100 hover:border-[color:var(--clf-color-primary)]'
              )}
            >
              <img
                src={src}
                alt={alt}
                loading="lazy"
                decoding="async"
                className="h-full w-full object-cover"
              />
            </button>
          );
        })}
      </div>

      {/* Right scroll arrow */}
      {needsScrollArrows && (
        <button
          aria-label="Scroll thumbnails right"
          onClick={(e) => {
            e.stopPropagation();
            scroll('right');
          }}
          className="shrink-0 p-0.5 rounded text-[color:var(--clf-color-muted-foreground)] hover:text-[color:var(--clf-color-primary)] transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-primary"
        >
          <ChevronRightIcon />
        </button>
      )}
    </div>
  );
}

/**
 * Dot carousel — overlaid on the image for horizontal and compact variants.
 * Shows dots (up to 7); if > 7 images shows a "3 / 9" counter instead.
 * Prev/next arrows are always rendered; they dim at the first/last image.
 */
function DotCarousel({
  total,
  activeIndex,
  onPrev,
  onNext,
  onSelect,
}: {
  total: number;
  activeIndex: number;
  onPrev: () => void;
  onNext: () => void;
  onSelect: (i: number) => void;
}): React.ReactElement {
  const showCounter = total > 7;

  const arrowBase =
    'absolute top-1/2 -translate-y-1/2 z-10 flex h-6 w-6 items-center justify-center ' +
    'rounded-full bg-black/40 text-white transition-all hover:bg-black/65 ' +
    'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-white';

  return (
    <>
      {/* Prev arrow */}
      <button
        aria-label="Previous image"
        onClick={(e) => {
          e.stopPropagation();
          onPrev();
        }}
        className={cn(arrowBase, 'left-1.5', activeIndex === 0 && 'opacity-30 pointer-events-none')}
      >
        <ChevronLeftIcon />
      </button>

      {/* Next arrow */}
      <button
        aria-label="Next image"
        onClick={(e) => {
          e.stopPropagation();
          onNext();
        }}
        className={cn(
          arrowBase,
          'right-1.5',
          activeIndex === total - 1 && 'opacity-30 pointer-events-none'
        )}
      >
        <ChevronRightIcon />
      </button>

      {/* Dots or numeric counter */}
      <div className="absolute bottom-2 left-0 right-0 z-10 flex items-center justify-center gap-1">
        {showCounter ? (
          <span className="rounded-full bg-black/50 px-2 py-0.5 text-xs font-medium text-white">
            {activeIndex + 1} / {total}
          </span>
        ) : (
          Array.from({ length: total }, (_, i) => (
            <button
              key={i}
              aria-label={`Image ${i + 1}`}
              onClick={(e) => {
                e.stopPropagation();
                onSelect(i);
              }}
              className={cn(
                'rounded-full bg-white transition-all duration-200',
                'focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-white',
                i === activeIndex ? 'h-1.5 w-4' : 'h-1.5 w-1.5 opacity-55 hover:opacity-90'
              )}
            />
          ))
        )}
      </div>
    </>
  );
}

// ─── Main component ───────────────────────────────────────────────────────────

export const ProductCard = forwardRef<HTMLDivElement, ProductCardProps>(function ProductCard(
  {
    product,
    variant = 'default',
    isLoading = false,
    isWishlisted = false,
    showRating = true,
    currency = '$',
    addToCartLabel = 'Add to Cart',
    onAddToCart,
    onWishlistToggle,
    onCardClick,
    renderBadge,
    classNames,
    className,
    style,
  },
  ref
) {
  const isDesktop = useMediaQuery('(min-width: 1024px)');
  const isHorizontal = variant === 'horizontal';
  const isCompact = variant === 'compact';
  const inStock = product.inStock !== false;
  const discount = product.originalPrice
    ? calculateDiscount(product.originalPrice, product.price)
    : 0;

  // Normalise image list: images[] takes precedence; fallback to single image
  const allImages: string[] = product.images?.length ? product.images : [product.image];
  const allAlts: string[] = allImages.map(
    (_, i) =>
      product.imageAlts?.[i] ??
      (i === 0 ? (product.imageAlt ?? product.name) : `${product.name} — image ${i + 1}`)
  );
  const hasMultiple = allImages.length > 1;

  const [activeIndex, setActiveIndex] = useState(0);
  const activeImage = allImages[activeIndex] ?? product.image;
  const activeAlt = allAlts[activeIndex] ?? product.name;

  const goPrev = useCallback(() => setActiveIndex((i) => Math.max(0, i - 1)), []);
  const goNext = useCallback(
    () => setActiveIndex((i) => Math.min(allImages.length - 1, i + 1)),
    [allImages.length]
  );

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLDivElement>) => {
      if ((e.key === 'Enter' || e.key === ' ') && onCardClick) {
        e.preventDefault();
        onCardClick(product);
      }
    },
    [onCardClick, product]
  );

  const handleCardClick = useCallback(() => {
    onCardClick?.(product);
  }, [onCardClick, product]);

  if (isLoading) return <SkeletonCard variant={variant} />;

  const badgeNode = renderBadge
    ? renderBadge(product)
    : (() => {
        const bv = resolveBadgeVariant(product);
        if (!bv) return null;
        const labels: Record<string, string> = {
          sale: discount > 0 ? `${discount}% OFF` : 'Sale',
          'out-of-stock': 'Out of Stock',
        };
        return <Badge variant={bv} label={labels[bv] ?? ''} className={classNames?.badge} />;
      })();

  // Which multi-image UI to render (only when hasMultiple)
  const useDotCarousel = hasMultiple && (isHorizontal || isCompact);
  const useThumbnailStrip = hasMultiple && !isHorizontal && !isCompact;

  return (
    <div
      ref={ref}
      role={onCardClick ? 'button' : 'article'}
      tabIndex={onCardClick ? 0 : undefined}
      onClick={onCardClick ? handleCardClick : undefined}
      onKeyDown={onCardClick ? handleKeyDown : undefined}
      style={style}
      className={cn(
        'w-full group relative rounded-lg bg-[color:var(--clf-color-surface)] shadow-sm',
        'border border-[color:var(--clf-color-border)] overflow-hidden transition-shadow hover:shadow-md',
        onCardClick &&
          'cursor-pointer focus-visible:ring-2 focus-visible:ring-primary focus-visible:outline-none',
        isHorizontal ? 'flex flex-row' : 'flex flex-col',
        classNames?.root,
        className
      )}
    >
      {/* ── Image area ── */}
      <div
        className={cn(
          'relative overflow-hidden bg-[color:var(--clf-color-surface-raised)]',
          isHorizontal ? 'w-24 shrink-0 sm:w-32' : isCompact ? 'h-36' : 'h-56 sm:h-64',
          classNames?.image
        )}
      >
        <img
          src={activeImage}
          alt={activeAlt}
          loading="lazy"
          decoding="async"
          className="h-full w-full object-cover transition-transform duration-[var(--clf-duration-slow)] group-hover:scale-105"
        />

        {/* Badge */}
        {badgeNode && <div className="absolute left-2 top-2">{badgeNode}</div>}

        {/* Wishlist */}
        {onWishlistToggle && (
          <div className="absolute right-2 top-2">
            <IconButton
              icon={<HeartIcon filled={isWishlisted} />}
              aria-label={isWishlisted ? 'Remove from wishlist' : 'Add to wishlist'}
              size="sm"
              variant="ghost"
              isActive={isWishlisted}
              onClick={(e) => {
                e.stopPropagation();
                onWishlistToggle(product);
              }}
              className="bg-[color:var(--clf-color-surface)]/80 backdrop-blur-sm"
            />
          </div>
        )}

        {/* Dot carousel — horizontal & compact only */}
        {useDotCarousel && (
          <DotCarousel
            total={allImages.length}
            activeIndex={activeIndex}
            onPrev={goPrev}
            onNext={goNext}
            onSelect={setActiveIndex}
          />
        )}

        {/* Quick-add overlay — desktop default only */}
        {isDesktop && onAddToCart && inStock && !isCompact && !isHorizontal && (
          <div className="absolute inset-x-0 bottom-0 translate-y-full bg-[color:var(--clf-color-surface)]/90 p-2 transition-transform duration-[var(--clf-duration-base)] group-hover:translate-y-0">
            <Button
              variant="primary"
              size="sm"
              fullWidth
              onClick={(e: React.MouseEvent) => {
                e.stopPropagation();
                onAddToCart(product);
              }}
              aria-label={`Quick add ${product.name} to cart`}
            >
              Quick Add
            </Button>
          </div>
        )}
      </div>

      {/* ── Thumbnail strip — default variant only ── */}
      {useThumbnailStrip && (
        <ThumbnailStrip
          images={allImages}
          imageAlts={allAlts}
          activeIndex={activeIndex}
          onSelect={setActiveIndex}
          className={classNames?.thumbnails}
        />
      )}

      {/* ── Body ── */}
      <div
        className={cn(
          'flex flex-1 flex-col min-w-0',
          isCompact ? 'p-2 gap-1' : 'p-4 gap-2',
          classNames?.body
        )}
      >
        <h3
          className={cn(
            'font-semibold leading-snug line-clamp-2',
            isCompact ? 'text-sm' : 'text-base',
            classNames?.title
          )}
        >
          {product.name}
        </h3>

        {showRating && product.rating !== undefined && !isCompact && (
          <StarRating rating={product.rating} count={product.reviewCount} />
        )}

        <div className={cn('flex items-baseline gap-2 flex-wrap', classNames?.price)}>
          <span className={cn('font-bold', isCompact ? 'text-sm' : 'text-lg')}>
            {formatPrice(product.price, currency)}
          </span>
          {product.originalPrice && product.originalPrice > product.price && (
            <span className="text-sm text-[color:var(--clf-color-muted-foreground)] line-through">
              {formatPrice(product.originalPrice, currency)}
            </span>
          )}
        </div>

        {!isCompact && onAddToCart && (
          <div className={cn('mt-auto pt-2', classNames?.actions)}>
            <Button
              variant="primary"
              size={isHorizontal ? 'sm' : 'md'}
              fullWidth
              isDisabled={!inStock}
              onClick={(e: React.MouseEvent) => {
                e.stopPropagation();
                onAddToCart(product);
              }}
              aria-label={
                inStock ? `${addToCartLabel}: ${product.name}` : `${product.name} is out of stock`
              }
            >
              {inStock ? addToCartLabel : 'Out of Stock'}
            </Button>
          </div>
        )}
      </div>
    </div>
  );
});
