﻿import React, { memo } from 'react';
import { cn } from '@/utils/cn';
import { formatPrice } from '@/utils/formatPrice';
import { IconButton } from '@/primitives/IconButton';
import { TrashIcon, MinusIcon, PlusIcon } from '@icons';
import type { CartItemProps } from './CartDrawer.types';

const stepperBtnBase = [
  'flex h-7 w-7 items-center justify-center',
  'text-[color:var(--clf-color-muted-foreground)] transition-colors',
  'hover:bg-[color:var(--clf-color-surface-raised)] hover:text-[color:var(--clf-color-primary)]',
  'disabled:cursor-not-allowed disabled:opacity-40',
  'focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-inset',
  'focus-visible:ring-[color:var(--clf-color-primary)]',
].join(' ');

/**
 * A single line item inside the CartDrawer.
 * Wrapped in React.memo so it only re-renders when its own props change.
 */
export const CartItemComponent = memo(function CartItemComponent({
  item,
  currency = '$',
  onQuantityChange,
  onRemove,
  className,
}: CartItemProps): React.ReactElement {
  return (
    <div className={cn('flex gap-3 py-3', className)}>
      {/* Thumbnail */}
      <div className="relative h-16 w-16 shrink-0 overflow-hidden rounded-md bg-[color:var(--clf-color-surface-raised)]">
        <img
          src={item.image}
          alt={item.name}
          loading="lazy"
          decoding="async"
          className="h-full w-full object-cover"
        />
      </div>

      {/* Info column */}
      <div className="flex min-w-0 flex-1 flex-col gap-1">
        <p className="truncate text-sm font-medium leading-snug">{item.name}</p>
        <p className="text-sm font-bold text-[color:var(--clf-color-primary)]">
          {formatPrice(item.price, currency)}
        </p>

        {/* Quantity stepper + remove */}
        <div className="mt-auto flex items-center justify-between">
          <div
            role="group"
            aria-label={`Quantity for ${item.name}`}
            className="flex items-center overflow-hidden rounded-md border border-[color:var(--clf-color-border)]"
          >
            <button
              type="button"
              aria-label={`Decrease quantity of ${item.name}`}
              disabled={item.quantity <= 1}
              onClick={() => onQuantityChange(item.id, item.quantity - 1)}
              className={cn(stepperBtnBase, 'border-r border-[color:var(--clf-color-border)]')}
            >
              <MinusIcon />
            </button>
            <span
              className="w-8 select-none text-center text-sm font-medium"
              aria-live="polite"
              aria-label={`Quantity: ${item.quantity}`}
            >
              {item.quantity}
            </span>
            <button
              type="button"
              aria-label={`Increase quantity of ${item.name}`}
              onClick={() => onQuantityChange(item.id, item.quantity + 1)}
              className={cn(stepperBtnBase, 'border-l border-[color:var(--clf-color-border)]')}
            >
              <PlusIcon />
            </button>
          </div>

          <IconButton
            icon={<TrashIcon />}
            aria-label={`Remove ${item.name} from cart`}
            size="sm"
            variant="ghost"
            onClick={() => onRemove(item.id)}
            className="text-[color:var(--clf-color-danger)] hover:bg-[color:var(--clf-color-danger)]/10"
          />
        </div>
      </div>
    </div>
  );
});
